--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelPopupGift:OnModelInit()
    self:ModelNetMsgRecv(LProtoIds.PopupGiftNowListResp, function(...)
        self:OnPopupGiftNowListResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.PopupGiftNowResp, function(...)
        self:OnPopupGiftNowResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.PopupGiftBuyResp, function(...)
        self:OnPopupGiftBuyResp(...)
    end)
    self:ModelNetMsgRecv(LProtoIds.PopupGiftSelectResp, function(...)
    end)

    self:ModelNetMsgRecv(LProtoIds.PopupGiftOptionalInfoResp, function(...)
        self:OnPopupGiftOptionalInfoResp(...)
    end)

    self:ModelEventRecv(EventNames.ON_ACTIVITY_CONFIG_DATA, function(...)
        if (self._tmpActivityPopDataList) then
            self:SetActivityPopupList(self._tmpActivityPopDataList)--活动93弹框礼包 GetWebActivityDataById 为空时走此返回刷新数据
        end
    end)

    self._wndStr = {
        "UIFightPrepare",
        "UIFight",
        "WndMirror",
        "UIMirNew",
        "UIEqCompound",
        "UIBags",
    }

    self._giftTypeWnd = {
        [0] = "UIPop2Gift",
        [1] = "UIPop4Gift",
        [2] = "UIPop5Gift"
    }

    self._giftArrList = {}
    self._popupRecord = {}
    self:InitSetGiftArr()
end

--在协议数据处理完之后需要调用finish
function ModelPopupGift:OnModelRequest()
    self._timer = LxTimer:New()
    self:OnPopupGiftNowListReq()
    self:OnPopupGiftOptionalInfoReq()
    self:ModelFinish()
end

