function ModelPopupGift:SetGiftsList(pb)
    local gift = StructPopupGiftNowInfo:New()
    gift:CreateByPb(pb)
    local ref = self:GetPopupGiftRefByRefId(gift.refId)
    if not ref then
        printErrorN(string.format("ModelPopupGift not ref %s", gift.refId))
        return
    end
    local giftGroup = ref.giftGroup
    local giftShowType = ref.giftShowType
    gift.giftGroup = giftGroup
    gift.ref = ref
    if giftShowType and giftShowType == 2 then
        --- http://192.168.16.2:3002/issues/347
        --- 代码删除
    else
        local _gift = self._gifts or {}
        local giftByRefId = self._giftByRefId or {}
        if (ref and gift.endTime > 0) then
            _gift[gift.id] = gift
            giftByRefId[ref.refId] = gift
        else
            _gift[gift.id] = nil
            giftByRefId[ref.refId] = nil
        end
        self._gifts = _gift
        self._giftByRefId = giftByRefId
    end

    return gift
end

function ModelPopupGift:OnPopupGiftNowResp(pb)

    local pbGifts = pb.gift
    local gifts = {}
    local giftSecs = {}
    local giftFirsts = {}
    for k, v in ipairs(pbGifts) do
        --当前限时礼包
        local gift = self:SetGiftsList(v)
        if gift then
            local giftType = gift.ref.giftType
            if giftType == 2 then
                table.insert(giftFirsts, gift)
            elseif giftType == 1 then
                table.insert(giftSecs, gift)
            else
                table.insert(gifts, gift)
            end

        end
    end

    for k, v in ipairs(giftSecs) do
        table.insert(giftFirsts, v)
    end

    for k, v in ipairs(gifts) do
        table.insert(giftFirsts, v)
    end

    self:ResetDataTimer()

    for k, gift in ipairs(giftFirsts) do
        local attr = self:FormatPopGiftStr(gift)
        gLxTKData:OnTAClientEventReq(LxTKData.CLIENT_POPUP_GIFT, "popup_auto", attr)

        local bOpen = true
        local wndData = nil
        local isImeadiate = gift.ref.popupType == 1

        if gift.specialGiftRef then
            wndData = {
                uiName = "UIPop3Gift",
                para = {
                    id = gift.id,
                    showGroup = gift.specialGiftRef.showGroup,
                    ignoreMap = isImeadiate,
                    ignoreWnd = isImeadiate,
                }

            }

            if GF.FindFirstWndByName("UIPop3Gift") then
                self._popupRecord[wndData.para.id] = true
                bOpen = false
            end
        else
            local giftType = gift.ref.giftType
            local giftShowType = gift.ref.giftShowType
            --local wndGiftName = giftType == 0 and "UIPop2Gift" or "UIPop4Gift"
            local wndGiftName = gModelPopupGift:GetPopupGiftNameByGiftType(giftType, giftShowType)
            wndData = {
                uiName = wndGiftName,
                para = {
                    id = gift.id,
                    ignoreMap = isImeadiate,
                    ignoreWnd = isImeadiate,
                },
            }
            if self:CheckPopupWndOpen() then
                self._popupRecord[wndData.para.id] = true
                bOpen = false
            end
        end

        if bOpen and not self._popupRecord[wndData.para.id] then
            self._popupRecord[wndData.para.id] = true
            gModelWndPop:TryOpenPopWnd(wndData.uiName, wndData.para)
        end
    end
end
function ModelPopupGift:CheckPopupWndOpen(wndName)
    if string.isempty(wndName) then
        if GF.FindFirstWndByName("UIPop2Gift") or
                GF.FindFirstWndByName("UIPop4Gift") or GF.FindFirstWndByName("UIPop5Gift")  then
            return true
        end
    else
        if GF.FindFirstWndByName(wndName) then
            return true
        end
    end
    return false
end

function ModelPopupGift:GetGiftIndex(id)
    local list = self:GetGiftArrList()
    for i, v in ipairs(list) do
        if (v.id == id) then
            return i
        end
    end
end

