function ModelPopupGift:GetSpecialGiftListByKey(giftGroup)
    local list = {}
    local gifts = self:GetSpecialGiftsByGiftGroup(giftGroup)
    for i, v in pairs(gifts) do
        table.insert(list, v)
    end
    table.sort(list, function(a, b)
        return a.endTime < b.endTime
    end)
    return list
