--sid:参数为活动sid,旧弹框礼包不传
function ModelPopupGift:GetGiftByRefId(refId, sid)
    local giftByRefId = self._giftByRefId
    if (sid) then
        if not giftByRefId or table.isempty(giftByRefId[refId]) then
            giftByRefId = (self._activityGiftList and self._activityGiftList[sid]) and self._activityGiftList[sid][refId] or nil
            return giftByRefId
        end
    end
    return giftByRefId[refId]
end

function ModelPopupGift:GetGiftByGroup(giftGroup, sid)
    local arr = self._giftArrList[giftGroup] and table.light_copy(self._giftArrList[giftGroup]) or {}
    if (sid and self._activityGiftArrList and self._activityGiftArrList[sid]) then
        local activityArr = self._activityGiftArrList[sid][giftGroup]
        if (activityArr and #activityArr) then
            for i, v in pairs(activityArr) do
                table.insert(arr, v)
            end
        end
    end
    table.sort(arr, function(a, b)
        return a.giftGroupCount < b.giftGroupCount
    end)

    for k, v in ipairs(arr) do
        local gift = self:GetGiftByRefId(v.refId, v.sid)
        if gift then
            return gift
        end
    end
end

function ModelPopupGift:GetGiftByGroup_NoSid(giftGroup)
    local arr = self._giftArrList[giftGroup] and table.light_copy(self._giftArrList[giftGroup]) or {}

    return arr
end

function ModelPopupGift:GetGiftArrList()
    --获取礼包列表
    local list = {}
    local gifts = self:GetGiftList()
    for i, v in pairs(gifts) do
        table.insert(list, v)
    end
    table.sort(list, function(a, b)
        local aSort = a.ref.sort
        local bSort = b.ref.sort
        return aSort < bSort
    end)
    ---活动弹框礼包
    local activityGifts = self:GetActivityPopupList()
    if (activityGifts) then
        for i, v in pairs(activityGifts) do
            for j, k in pairs(v) do
                table.insert(list, k)
            end
        end
    end
    return list
end
function ModelPopupGift:GetGiftArrListByGiftType(giftType)
    giftType = giftType or 0
    local list = {}
    local gifts = self:GetGiftList()
    for i, v in pairs(gifts) do
        if v.ref.giftType == giftType then
            table.insert(list, v)
        end
    end
    table.sort(list, function(a, b)
        local aSort = a.ref.sort
        local bSort = b.ref.sort
        return aSort < bSort
    end)

    local sortActs = {}
    ---活动弹框礼包
    local activityGiftData = self:GetActivityPopupList()
    if activityGiftData then
        for i, v in pairs(activityGiftData) do
            for j, k in pairs(v) do
                if k.ref.giftType == giftType then
                    table.insert(sortActs, k)
                end
            end
        end
        if #sortActs > 0 then
            table.sort(sortActs, function(a, b)
                return a.endTime < b.endTime
            end)
            for i, v in ipairs(sortActs) do
                table.insert(list, v)
            end
        end
    end
    return list
end

function ModelPopupGift:GetSortTime()
    if not self._gifts then
        return
    end

    local endTime
    for k, v in pairs(self._gifts) do
        if not endTime or v.endTime < endTime then
            endTime = v.endTime
        end
    end
    if not endTime then
        return
    end

    local timeLeft = endTime / 1000 - GetTimestamp()
    return timeLeft
end

