function ModelPopupGift:HasActivePopupGift()
    if not self._gifts then
        return
    end

    local endTime = 0
    local giftType = 0

    self._haveGiftType = self._haveGiftType or {}
    for k, v in pairs(self._gifts) do
        if not endTime or v.endTime > endTime then
            --endTime = endTime

            endTime = v.endTime
            giftType = v.ref.giftType

        end

        self._haveGiftType[v.ref.giftType] = true
    end

    if endTime / 1000 > GetTimestamp() then
        return true, giftType
    else
        return false, giftType
    end
end

function ModelPopupGift:GetSpecialPopupShow()
    if not self._specialGifts then
        return
    end

    local id, showGroup
    for k, v in pairs(self._specialGifts) do
        showGroup = k
        for k1, v1 in pairs(v) do
            id = k1
            break
        end
        if id then
            break
        end
    end

    return id, showGroup
end

