function ModelPopupGift:GetGiftArrByRefId(refId, sid)
    local list = {}
    local refList = self:GetPopupGiftRef()
    local ref = refList[refId]
    if (not ref and sid and self._activityGiftRef[sid]) then
        ref = self._activityGiftRef[sid][refId]
    end
    local giftGroup = ref and ref.giftGroup or nil
    if giftGroup and giftGroup > 0 then
        local arr = self._giftArrList[giftGroup] and table.light_copy(self._giftArrList[giftGroup]) or {}
        if (sid and self._activityGiftArrList and self._activityGiftArrList[sid]) then
            local activityArr = self._activityGiftArrList[sid][giftGroup]
            if (activityArr and #activityArr) then
                for i, v in pairs(activityArr) do
                    table.insert(arr, v)
                end
            end
        end
        list = arr or { ref }
    else
        list = { ref }
    end
    if (#list > 1) then
        table.sort(list, function(a, b)
            local endTimeA = a.endTime or 0
            local endTimeB = b.endTime or 0
            if endTimeA ~= endTimeB then
                return endTimeA < endTimeB
            end
            return a.giftGroupCount < b.giftGroupCount
        end)
    end
    return list
end

function ModelPopupGift:InitSetGiftArr()
    local refList = self:GetPopupGiftRef()
    for i, v in pairs(refList) do
        local giftGroup = v.giftGroup
        if giftGroup and giftGroup > 0 then
            local arr = self._giftArrList[giftGroup]
            if not arr then
                arr = {}
            end
            table.insert(arr, v)
            self._giftArrList[giftGroup] = arr
        end
    end
end

