function ModelPopupGift:GetPopGifListByGiftTypeAndDataList(giftType, popGiftList)
    local klist = {}
    if (not popGiftList) then
        return
    end
    for i, v in pairs(popGiftList) do
        for j, k in pairs(v) do
            if k.ref.giftType == giftType then
                klist[i] = klist[i] and klist[i] or {}
                local data = klist[i][k.giftGroup]
                if not data then
                    data = {}
                    data.sort = k.endTime
                    data.list = {}
                end
                table.insert(data.list, k)
                klist[i][k.giftGroup] = data
            end
        end
    end
    return klist
end

function ModelPopupGift:GetAllIdStr()
    local list = self:GetGiftArrList()
    local refIdList = {}
    local idList = {}
    for k, v in ipairs(list) do
        table.insert(refIdList, tostring(v.refId))
        table.insert(idList, tostring(v.id))
    end

    return table.concat(refIdList, ","), table.concat(idList, ",")
end

function ModelPopupGift:FormatPopGiftStr(giftData, extra)
    local seconds = math.floor(giftData.endTime / 1000 - GetTimestamp())
    local refId = giftData.refId
    local uniqueId = giftData.id

    if not extra then
        return string.format("%s,%s,%s", seconds, refId, uniqueId)
    else
        return string.format("%s,%s,%s,%s", seconds, refId, uniqueId, extra)
    end
end

--------------------------------------------------- 刷新计时器 ----------------------------------------------------------
function ModelPopupGift:ResetDataTimer()
    if not self._timer then
        self._timer = LxTimer:New()
    end
    local key = "resetData"
    self._timer:TimerRemoveByKey(key)
    local delayTime = self:GetSortTime()
    if not delayTime then
        return
    end

    delayTime = math.max(1, delayTime)

    printErrorN("----------------reset timer delay " .. delayTime)

    self._timer:TimerCreate(key, function()
        self:OnPopupGiftNowListReq()
    end, delayTime, false, 1)
end

function ModelPopupGift:GetGiftData(id, sid)
    local giftDataList = self:GetGiftList()
    ---活动弹框礼包
    if (not giftDataList[id] and sid) then
        local activityGifDataList = self:GetActivityPopupList()
        if (activityGifDataList[sid] and activityGifDataList[sid][id]) then
            return activityGifDataList[sid][id]
        end
    end
    --------
    return giftDataList[id]
end

function ModelPopupGift:BuyGift(refId, wndName, sid, customReward)
    local gift = self:GetGiftByRefId(refId, sid)
    if not gift then
        return
    end

    local id = gift.id
    local ref = gift.ref

    if not string.isempty(ref.rewardFree) then
        local freeList = string.split(ref.rewardFree, '|')
        local cnt = #freeList
        local giftReward = customReward and customReward or gift.reward
        local selectList = string.split(giftReward, ',')

        if cnt ~= #selectList then
            local str = ccClientText(14912)-- "请选择奖励道具"
            GF.ShowMessage(str)

            local marketData = {
                customList = ref.rewardFree,
                customGift = gift.reward
            }

            local giftData = {
                marketData = marketData
            }

            local giftName = ref.isActivity and ref.giftName or ccLngText(ref.giftName)
            local windType = ref.isActivity and 1 or 2
            local para = {
                wndType = windType,
                id = gift.id,
                itemIndex = 1,
                giftData = giftData,
                title = giftName,

                sid = ref.sid,
                pageId = ref.pageId,
                entryId = ref.refId
            }

            printInfoN("refId " .. ref.refId)
            GF.OpenWnd("UICumSelectNew", para)
            return
        end
    end
    local payType = ref.isActivity and ModelPay.PAY_TYPE_ACTIVITY or ModelPay.PAY_TYPE_GIFT
    local payGift = not ref.isActivity and ModelPay.PAY_GIFT_POPUPGIFT or nil
    if ref.buyType == ModelPopupGift.BUYTYPE_MONEY then
        gModelPay:GiftPayCtrl(id, tonumber(ref.expend), payType, payGift, ref.sid, ref.pageId)
    elseif ref.buyType == ModelPopupGift.BUYTYPE_FREE then
        if (not sid) then
            self:OnPopupGiftBuyReq(id)
        else
            gModelActivity:OnActivityMarkeyBuyReq(ref.sid, ref.pageId, id, 1)
            --gModelPay:GiftPayCtrl(id, tonumber(ref.expend), payType, payGift, ref.sid, ref.pageId)
        end
    else
        local item = LxDataHelper.ParseItem_3(ref.expend)
        local num = gModelItem:GetNumByRefId(item.itemId)
        if num < item.itemNum then
            gModelGeneral:OpenGetWayWnd({ itemId = item.itemId, srcWnd = wndName })
            return
        end
        if (not sid) then
            self:OnPopupGiftBuyReq(id)
        else
            gModelActivity:OnActivityMarkeyBuyReq(ref.sid, ref.pageId, id, 1)
            --gModelPay:GiftPayCtrl(id, tonumber(ref.expend), payType, payGift, ref.sid, ref.pageId)
        end
    end
end

function ModelPopupGift:GetSelectReward(refId)
    if not self._optionInfo then
        return
    end
    return self._optionInfo[refId]
end

---活动弹框礼包
---
---
function ModelPopupGift:GetActivityPopupList()
    return self._activityGiftList
end
function ModelPopupGift:SetActivityPopupList(dataList)
    self._activityGiftList = {}
    self._activityGiftArrList = {} --配置表根据giftGroup字段保存
    self._activityGiftRef = {}
    self._activityTryOpen = false --回主城弹框标记
    local activityGiftList = dataList
    for i, v in pairs(activityGiftList) do
        ---@type LActivityWebData
        local activityData = gModelActivity:GetWebActivityDataById(v.sid)
        if (not activityData) then
            self._tmpActivityPopDataList = dataList
            return
        end
        self._tmpActivityPopDataList = nil
        local showIdList = {}
        local popupActDataList = {}
        local moreInfoArra = JSON.decode(v.moreInfo)
        local giftIdList = moreInfoArra.giftIds
        local idCntList = {}
        if (v.status == 3) then
            self._activityGiftList[v.sid] = nil
            self._activityGiftArrList[v.sid] = nil
            self._activityGiftRef[v.sid] = nil
        end
        local insRefData = {}
        if (activityData and giftIdList and v.status ~= 3) then
            for ind, value in pairs(giftIdList) do
                showIdList[value] = true
            end
            for ind, value in pairs(moreInfoArra.popupActData) do
                popupActDataList[value.refId] = value
            end
            local activityChuck = activityData.chunk
            local entries = activityChuck[1].entries
            for j, k in pairs(entries) do
                local moreInfo = k.moreInfo
                local moreArr = string.split(moreInfo, "|")
                local iconArr = string.split(k.icon, "|")
                local descriptionArr = string.split(k.description, "|")
                local popRefId = 1001
                local popRef = self:GetPopupGiftRefByRefId(popRefId)
                -- local refData = table.clone(popRef)
                --modify
                local refData = {} --table.cloneKey(popRef,"giftshowlype","popupType","firePriority","lifetimeLimit","buyType","expendType")
                local giftEndTime = v.endTime * 1000
                if (popupActDataList and popupActDataList[k.id]) then
                    giftEndTime = popupActDataList[k.id].endTime
                end
                refData.sid = v.sid
                refData.isActivity = true
                refData.pageId = 1
                refData.expend1 = k.expend1
                ----
                --覆盖PopupGiftRef字段数据

                refData.refId = k.id
                refData.giftType = tonumber(moreArr[7]) == 2 and 0 or 1
                refData.icon = iconArr[2]
                refData.giftName = k.name
                refData.endTime = giftEndTime
                refData.giftGroup = tonumber(moreArr[1])
                refData.giftGroupCount = tonumber(moreArr[2])
                refData.giftNextGrade = moreArr[3]
                refData.activateType = tonumber(moreArr[4])
                refData.time = moreArr[5]
                refData.discount = k.discount
                refData.limit = k.personLimit
                refData.giftGradeName = descriptionArr[1]
                refData.buyBtnTxt = k.expendType == 0 and "" or descriptionArr[2]
                refData.description = descriptionArr[3]
                refData.descriptionSaleOut = descriptionArr[4]
                refData.reward = k.reward
                refData.rewardFree = k.rewardFree
                local showHeroInfo = string.split(iconArr[1], "=")
                local showHero
                local showXY
                local showScale
                if #showHeroInfo > 1 then
                    showHero = showHeroInfo[1]
                    showXY = showHeroInfo[2]
                    showScale = tonumber(showHeroInfo[3]) or 1
                else
                    showHero = iconArr[1]
                end
                refData.showHero = showHero
                refData.showXY = showXY
                refData.showScale = showScale
                -- 【G公共支持】删除国服网页充值的功能
                -- refData.webBuy = k.webBuy
                -- refData.webDesc = k.webDesc
                refData.descriptionNo = descriptionArr[5]

                ---特殊的使用特定配置 --modify

                refData.giftshowlype = popRef.giftshowlype
                refData.popupType = popRef.popupType
                refData.firePriority = popRef.firePriority
                refData.lifetimeLimit = popRef.lifetimeLimit
                refData.buyType = popRef.buyType
                refData.expendType = popRef.expendType

                if (k.expendType == 0) then
                    refData.buyType = 2
                elseif (k.expendType == 1) then
                    local expendArr = string.split(k.expend2, "|")
                    local currencyId = expendArr[2]
                    --判断消耗货币是否为钻石
                    refData.buyType = currencyId == "102001" and 1 or 3
                elseif (k.expendType == 2) then
                    refData.buyType = 0
                end
                if (k.expend2 and k.expend2 ~= "") then
                    refData.expend = k.expend2
                else
                    refData.expend = nil
                end
                -----
                idCntList[refData.giftType] = idCntList[refData.giftType] and idCntList[refData.giftType] + 1 or 1
                local activityGiftData = {
                    config = v,
                    entry = k,
                    isActivity = true,
                    -----原弹框礼包包含字段
                    buyNum = 0,
                    endTime = giftEndTime,
                    giftGroup = tonumber(moreArr[1]),
                    heroRefId = 0,
                    id = k.id,
                    ref = refData,
                    refId = k.id,
                    sid = v.sid
                }
                self._activityGiftList[activityGiftData.sid] = self._activityGiftList[activityGiftData.sid] and self._activityGiftList[activityGiftData.sid] or {}
                self._activityGiftList[activityGiftData.sid][activityGiftData.refId] = activityGiftData
                self._activityGiftArrList[activityGiftData.sid] = self._activityGiftArrList[activityGiftData.sid] and self._activityGiftArrList[activityGiftData.sid] or {}
                self._activityGiftArrList[activityGiftData.sid][refData.giftGroup] = self._activityGiftArrList[activityGiftData.sid][refData.giftGroup] and self._activityGiftArrList[activityGiftData.sid][refData.giftGroup] or {}
                self._activityGiftArrList[activityGiftData.sid][refData.giftGroup][j] = refData
                self._activityGiftRef = self._activityGiftRef and self._activityGiftRef or {}
                self._activityGiftRef[activityGiftData.sid] = self._activityGiftRef[activityGiftData.sid] and self._activityGiftRef[activityGiftData.sid] or {}
                self._activityGiftRef[activityGiftData.sid][refData.refId] = refData
                if (not self._activityTryOpen and (not refData.popupType or refData.popupType == 0)) then
                    if (popupActDataList[k.id] and popupActDataList[k.id].newGift == 1 and not insRefData[refData.giftType]) then
                        insRefData[refData.giftType] = refData
                    end
                end
            end
            self:SetShowActivGiftList(v.sid, showIdList)
        end

        local list = {}
        for i, v in pairs(insRefData) do
            if i == 1 then
                table.insert(list, v)
            end
        end
        for i, v in pairs(insRefData) do
            if i ~= 1 then
                table.insert(list, v)
            end
        end
        for i, v in ipairs(list) do
            self:ActTryOpenPopWnd(v)
        end
    end
    FireEvent(EventNames.REFRESH_ACTIVITY_POPGIFT_DATA)
end

function ModelPopupGift:SetShowActivGiftList(sid, showIdList)
    if (not self._activityGiftList or not self._activityGiftList[sid]) then
        return
    end
    local eTime
    for i, v in pairs(self._activityGiftList[sid]) do
        local giftGroup = v.giftGroup
        local showGift = false
        for j, k in pairs(self._activityGiftArrList[sid][giftGroup]) do
            if (showIdList[k.refId]) then
                showGift = true
                if (not eTime or k.endTime < eTime) then
                    eTime = k.endTime
                end
            end
        end
        if (not showGift) then
            self._activityGiftList[sid][i] = nil
            self._activityGiftRef[sid][i] = nil
            for o, p in pairs(self._activityGiftArrList[sid][giftGroup]) do
                if (p.refId == i) then
                    table.remove(self._activityGiftArrList[sid][giftGroup], o)
                end
            end
        end
    end
    if (eTime) then
        local timeLeft = eTime / 1000 - GetTimestamp()
        if timeLeft then
            timeLeft = math.max(1, timeLeft)
            if not self._timer then
                self._timer = LxTimer:New()
            end
            local key = "ActivityPopupWndTimeKey"
            self._timer:TimerRemoveByKey(key)
            self._timer:TimerCreate(key, function()
                gModelActivity:OnActivityPageReq(sid)
            end, timeLeft, false, 1)
        end
    end
end
function ModelPopupGift:GetActivityGiftArrListByGroup(sid, giftGroup)
    if (self._activityGiftArrList and self._activityGiftArrList[sid]) then
        return self._activityGiftArrList[sid][giftGroup]
    end
end
--回到主城触发弹框
function ModelPopupGift:ActTryOpenPopWnd(refData)
    self._activityTryOpen = true
    local giftType = refData.giftType
    --local wndGiftName = giftType == 0 and "UIPop2Gift" or "UIPop4Gift"
    local wndGiftName = self:GetPopupGiftNameByGiftType(giftType, refData.giftShowType)
    local wndData = {
        uiName = wndGiftName,
        para = {
            id = refData.refId,
            ignoreMap = false,
            ignoreWnd = false,
        },
    }

    local id = wndData.para.id
    if self._popupRecord[id] then
        return
    end
    if id then
        self._popupRecord[id] = true
    end

    if self:CheckPopupWndOpen() then
        return
    end

    gModelWndPop:TryOpenPopWnd(wndData.uiName, wndData.para)
end

function ModelPopupGift:GetPopupGiftNameByGiftType(giftType, giftShowType)
    return self._giftTypeWnd[giftType]
    --return giftType == 0 and "UIPop2Gift" or "UIPop4Gift"
end

return ModelPopupGift